sql:
SELECT name
FROM university
WHERE university_id = 1;

SELECT name
FROM university
WHERE university_id = (SELECT university_id FROM faculty WHERE faculty_id = 0);

SELECT name
FROM university
WHERE founding_year = (SELECT MIN(founding_year) FROM university);

SELECT name, founding_year
FROM university
ORDER BY founding_year DESC;

SELECT COUNT(*) AS number_of_universities
FROM university
WHERE region = 'West';

SELECT region, COUNT(*) AS num_universities
FROM university
GROUP BY region;
